# Load the PyTorch model
model = torch.hub.load('pytorch/vision:v0.10.0', 'resnet18', pretrained=True)

class ImageClassifierAPI:
    def __init__(self):
        self.transform = transforms.Compose([
            transforms.Resize(256),
            transforms.CenterCrop(224),
            transforms.ToTensor(),
            transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225])
        ])

    def run_inference(self, image):
        output = model(image)
        _, predicted_class = torch.max(output, 1)
        confidence_score = torch.softmax(output, dim=1)[predicted_class].item()
        return predicted_class.item(), confidence_score

    def handle_request(self, event):
        if 'image' in event:
            image_data = event['image']
            image = Image.open(BytesIO(image_data))
            image = self.transform(image)
            image = image.unsqueeze(0).to(device=torch.device("cuda" if torch.cuda.is_available() else "cpu"))
            predicted_class, confidence_score = self.run_inference(image)
            return {'predicted_class': predicted_class, 'confidence_score': confidence_score}
        else:
            raise Exception('Missing required field: image')

